14	use std::{
15	    env, fmt,
16	    path::Path,
17	    sync::{Arc, Mutex, MutexGuard},
18	};
19	
20	use serde::{Deserialize, Serialize};
21	use zenoh_config::ExpandedConfig;
22	use zenoh_result::{bail, ZResult};
23	
24	/// Zenoh configuration.
25	///
26	/// The zenoh configuration is unstable, so no direct access to the fields is provided.
27	/// The only way to change the configuration is to load the JSON configuration from a file or a string,
28	/// with [`Config::from_file`](crate::config::Config::from_file) or
29	/// [`Config::from_json5`](crate::config::Config::from_json5),
30	/// or to use the [`Config::insert_json5`](crate::config::Config::insert_json5)
31	/// and [`Config::remove`](crate::config::Config::remove) methods to modify the configuration tree.
32	///
33	/// Example configuration file:
34	#[doc = concat!(
35	    "```json5\n",
36	    include_str!("../../DEFAULT_CONFIG.json5"),
37	    "\n```"
38	)]
39	///
40	/// Most options are optional as a way to keep defaults flexible. Some of the options have different
41	/// default values depending on the rest of the configuration.
42	///
43	#[derive(Default, Debug, Clone, Serialize, Deserialize)]
44	pub struct Config(pub(crate) zenoh_config::Config);
45	
46	impl Config {
47	    /// Default environment variable containing the file path used in [`Config::from_env`].
48	    pub const DEFAULT_CONFIG_PATH_ENV: &'static str = "ZENOH_CONFIG";
49	
50	    /// Load configuration from the file path specified in the [`Self::DEFAULT_CONFIG_PATH_ENV`]
51	    /// environment variable.
52	    pub fn from_env() -> ZResult<Self> {
53	        let path = env::var(Self::DEFAULT_CONFIG_PATH_ENV)?;
54	        Ok(Config(zenoh_config::Config::from_file(Path::new(&path))?))
55	    }
56	
57	    /// Load configuration from the file at `path`.
58	    pub fn from_file<P: AsRef<Path>>(path: P) -> ZResult<Self> {
59	        Ok(Config(zenoh_config::Config::from_file(path)?))
60	    }
61	
62	    /// Load configuration from the JSON5 string `input`.
63	    pub fn from_json5(input: &str) -> ZResult<Config> {
64	        match zenoh_config::Config::from_deserializer(&mut json5::Deserializer::from_str(input)?) {
65	            Ok(config) => Ok(Config(config)),
66	            Err(Ok(_)) => {
67	                Err(zerror!("The config was correctly deserialized, but it is invalid").into())
68	            }
69	            Err(Err(err)) => Err(err.into()),
70	        }
71	    }
72	
73	    pub fn remove<K: AsRef<str>>(&mut self, key: K) -> ZResult<()> {
74	        self.0.remove(key.as_ref())
75	    }
76	
77	    /// See [`zenoh_config::Config::try_remove_json5_array_item`].
78	    pub fn try_remove_json5_array_item<K: AsRef<str>>(&mut self, key: K) -> ZResult<bool> {
79	        self.0.try_remove_json5_array_item(key)
80	    }
81	
82	    /// Inserts configuration value `value` at `key`.
83	    pub fn insert_json5(&mut self, key: &str, value: &str) -> ZResult<()> {
84	        self.0
85	            .insert_json5(key, value)
86	            .map_err(|err| zerror!("{err}").into())
87	    }
88	
89	    /// See [`zenoh_config::Config::try_insert_json5_array_item`].
90	    pub fn try_insert_json5_array_item(&mut self, key: &str, value: &str) -> ZResult<bool> {
91	        self.0
92	            .try_insert_json5_array_item(key, value)
93	            .map_err(|err| zerror!("{err}").into())
94	    }
95	
96	    /// Returns a JSON string containing the configuration at `key`.
97	    pub fn get_json(&self, key: &str) -> ZResult<String> {
98	        self.0.get_json(key).map_err(|err| zerror!("{err}").into())
99	    }
100	
101	    // REVIEW(fuzzypixelz): the error variant of the Result is a Result because this does
102	    // deserialization AND validation.
103	    #[zenoh_macros::unstable]
104	    // TODO(yellowhatter): clippy says that Error here is extremely large (1k)
105	    #[allow(clippy::result_large_err)]
106	    pub fn from_deserializer<'d, D: serde::Deserializer<'d>>(
107	        d: D,
108	    ) -> Result<Self, Result<Self, D::Error>>
109	    where
110	        Self: serde::Deserialize<'d>,
111	    {
112	        match zenoh_config::Config::from_deserializer(d) {
113	            Ok(config) => Ok(Config(config)),
114	            Err(result) => match result {
115	                Ok(config) => Err(Ok(Config(config))),
116	                Err(err) => Err(Err(err)),
117	            },
118	        }
119	    }
120	}
121	
122	#[zenoh_macros::unstable]
123	impl std::ops::Deref for Config {
124	    type Target = zenoh_config::Config;
125	
126	    fn deref(&self) -> &Self::Target {
127	        &self.0
128	    }
129	}
130	
131	#[zenoh_macros::unstable]
132	impl std::ops::DerefMut for Config {
133	    fn deref_mut(&mut self) -> &mut <Self as std::ops::Deref>::Target {
134	        &mut self.0
135	    }
136	}
137	
138	#[doc(hidden)]
139	impl From<zenoh_config::Config> for Config {
140	    fn from(value: zenoh_config::Config) -> Self {
141	        Self(value)
142	    }
143	}
144	
145	impl fmt::Display for Config {
146	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
147	        write!(f, "{}", &self.0)
148	    }
149	}
150	
151	pub type Notification = Arc<str>;
152	
153	struct NotifierInner<T> {
154	    inner: Mutex<T>,
155	    subscribers: Mutex<Vec<flume::Sender<Notification>>>,
156	}
157	
158	/// The wrapper for a [`Config`] that allows to subscribe to changes.
159	/// This type is returned by [`Session::config`](crate::Session::config) and allows
160	/// the `Session` to immediately react to changes applied to the configuration.
161	pub struct Notifier<T> {
162	    inner: Arc<NotifierInner<T>>,
163	}
164	
165	impl<T> fmt::Debug for Notifier<T> {
166	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
167	        f.debug_tuple("Notifier").field(&"..").finish()
168	    }
169	}
170	
171	impl<T> Clone for Notifier<T> {
172	    fn clone(&self) -> Self {
173	        Self {
174	            inner: self.inner.clone(),
175	        }
176	    }
177	}
178	
179	fn ensure_config_key_is_dynamically_writable(key: &str) -> ZResult<()> {
180	    if !key.starts_with("plugins/") {
181	        bail!(
182	            "Error inserting conf value {} : updating config is only \
183	                supported for keys starting with `plugins/`",
184	            key
185	        );
186	    }
187	    Ok(())
188	}
189	
190	impl Notifier<ExpandedConfig> {
191	    pub fn new(inner: ExpandedConfig) -> Self {
192	        Notifier {
193	            inner: Arc::new(NotifierInner {
194	                inner: Mutex::new(inner),
195	                subscribers: Mutex::new(Vec::new()),
196	            }),
197	        }
198	    }
199	
200	    #[cfg(feature = "plugins")]
201	    pub fn subscribe(&self) -> flume::Receiver<Notification> {
202	        let (tx, rx) = flume::unbounded();
203	        self.lock_subscribers().push(tx);
204	        rx
205	    }
206	
207	    pub fn notify<K: AsRef<str>>(&self, key: K) {
208	        let key = key.as_ref();
209	        let key: Arc<str> = Arc::from(key);
210	        let mut marked = Vec::new();
211	        let mut subscribers = self.lock_subscribers();
212	
213	        for (i, sub) in subscribers.iter().enumerate() {
214	            if sub.send(key.clone()).is_err() {
215	                marked.push(i)
216	            }
217	        }
218	
219	        for i in marked.into_iter().rev() {
220	            subscribers.swap_remove(i);
221	        }
222	    }
223	
224	    pub fn lock(&self) -> MutexGuard<'_, ExpandedConfig> {
225	        self.lock_config()
226	    }
227	
228	    fn lock_subscribers(&self) -> MutexGuard<'_, Vec<flume::Sender<Notification>>> {
229	        self.inner
230	            .subscribers
231	            .lock()
232	            .expect("acquiring Notifier's subscribers Mutex should not fail")
233	    }
234	
235	    fn lock_config(&self) -> MutexGuard<'_, ExpandedConfig> {
236	        self.inner
237	            .inner
238	            .lock()
239	            .expect("acquiring Notifier's Config Mutex should not fail")
240	    }
241	
242	    pub fn remove<K: AsRef<str>>(&self, key: K) -> ZResult<()> {
243	        self.lock_config().remove(key.as_ref())?;
244	        self.notify(key);
245	        Ok(())
246	    }
247	
248	    pub fn try_remove_json5_array_item<K: AsRef<str>>(&self, key: K) -> ZResult<bool> {
249	        let applied = self
250	            .lock_config()
251	            .try_remove_json5_array_item(key.as_ref())?;
252	        if applied {
253	            self.notify(key);
254	        }
255	        Ok(applied)
256	    }
257	
258	    pub fn insert_json5(&self, key: &str, value: &str) -> ZResult<()> {
259	        ensure_config_key_is_dynamically_writable(key)?;
260	        self.lock_config().insert_json5(key, value)?;
261	        self.notify(key);
262	        Ok(())
263	    }
264	
265	    pub fn try_insert_json5_array_item(&self, key: &str, value: &str) -> ZResult<bool> {
266	        ensure_config_key_is_dynamically_writable(key)?;
267	        let applied = self.lock_config().try_insert_json5_array_item(key, value)?;
268	        if applied {
269	            self.notify(key);
270	        }
271	        Ok(applied)
272	    }
273	}
274	
275	#[cfg(test)]
276	mod tests {
277	    use zenoh_config::{InterceptorFlow, QosOverwriteItemConf};
278	
279	    use crate::Config;
280	
281	    #[test]
282	    fn runtime_try_insert_json5_array_item_rejects_non_plugin_keys() {
283	        let config = super::Notifier::new(zenoh_config::Config::default().expanded());
284	        let before = config.lock().get_json("qos/network").unwrap();
285	
286	        let err = config
287	            .try_insert_json5_array_item(
288	                "qos/network/id=item1",
289	                r#"{
290	                    id: "item1",
291	                    messages: ["put"],
292	                    key_exprs: ["**"],
293	                    overwrite: { priority: "real_time" },
294	                    flows: ["egress"]
295	                }"#,
296	            )
297	            .unwrap_err();
298	
299	        assert!(err
300	            .to_string()
301	            .contains("supported for keys starting with `plugins/`"));
302	        assert_eq!(config.lock().get_json("qos/network").unwrap(), before);
303	    }
304	
305	    #[test]
306	    fn insert_remove_json5_array_item() {
307	        let mut config = Config::default();
308	
309	        let item1 = r#"{
310	            id: "item1",
311	            messages: ["put"],
312	            key_exprs: ["**"],
313	            overwrite: {
314	                priority: "real_time",
315	            },
316	            flows: ["egress"]
317	        }"#;
318	        assert!(config
319	            .try_insert_json5_array_item("qos/network/id=item1", item1)
320	            .unwrap());
321	        let items = serde_json::from_str::<Vec<QosOverwriteItemConf>>(
322	            &config.get_json("qos/network").unwrap(),
323	        )
324	        .unwrap();
325	        assert_eq!(items.len(), 1);
326	        assert_eq!(items[0].id.as_ref().unwrap(), "item1");
327	        assert_eq!(
328	            *items[0].flows.as_ref().unwrap().first(),
329	            InterceptorFlow::Egress
330	        );
331	
332	        let item1 = r#"{
333	            id: "item1",
334	            messages: ["put"],
335	            key_exprs: ["**"],
336	            overwrite: {
337	                priority: "real_time",
338	            },
339	            flows: ["ingress"]
340	        }"#;
341	        assert!(config
342	            .try_insert_json5_array_item("qos/network/id=item1", item1)
343	            .unwrap());
344	        let items = serde_json::from_str::<Vec<QosOverwriteItemConf>>(
345	            &config.get_json("qos/network").unwrap(),
346	        )
347	        .unwrap();
348	        assert_eq!(items.len(), 1);
349	        assert_eq!(items[0].id.as_ref().unwrap(), "item1");
350	        assert_eq!(
351	            *items[0].flows.as_ref().unwrap().first(),
352	            InterceptorFlow::Ingress
353	        );
354	
355	        let item2 = r#"{
356	            id: "item2",
357	            messages: ["put"],
358	            key_exprs: ["**"],
359	            overwrite: {
360	                priority: "real_time",
361	            },
362	            flows: ["egress"]
363	        }"#;
364	        assert!(config
365	            .try_insert_json5_array_item("qos/network/id=item2", item2)
366	            .unwrap());
367	        let items = serde_json::from_str::<Vec<QosOverwriteItemConf>>(
368	            &config.get_json("qos/network").unwrap(),
369	        )
370	        .unwrap();
371	        assert_eq!(items.len(), 2);
372	        assert_eq!(items[0].id.as_ref().unwrap(), "item1");
373	        assert_eq!(
374	            *items[0].flows.as_ref().unwrap().first(),
375	            InterceptorFlow::Ingress
376	        );
377	        assert_eq!(items[1].id.as_ref().unwrap(), "item2");
378	        assert_eq!(
379	            *items[1].flows.as_ref().unwrap().first(),
380	            InterceptorFlow::Egress
381	        );
382	
383	        assert!(config
384	            .try_remove_json5_array_item("qos/network/id=item2")
385	            .unwrap());
386	        let items = serde_json::from_str::<Vec<QosOverwriteItemConf>>(
