383	    type Value = WhatAmIMatcher;
384	    fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
385	        write!(
386	            formatter,
387	            "a list of whatami variants ('{}', '{}', '{}')",
388	            WhatAmI::STR_R,
389	            WhatAmI::STR_P,
390	            WhatAmI::STR_C
391	        )
